import React, { useEffect, useState } from "react";

const apiBase = "https://prasa-backend-1.onrender.com";

export default function AddTicket({ employee }) {
  const [form, setForm] = useState({
    ticket_date: "",
    purpose: "",
    assigned_to: "",
    amount: "",
  });

  const [history, setHistory] = useState([]);
  const [message, setMessage] = useState("");
  const [filterMonth, setFilterMonth] = useState("");

  // Load ticket history
  const loadHistory = async () => {
    try {
      const res = await fetch(`${apiBase}/ticket-expenses`);
      const data = await res.json();

      setHistory(
        data.filter((t) => t.employee_id === employee.employee_id)
      );
    } catch (err) {
      console.error("History error:", err);
      setMessage("❌ Could not load ticket history");
    }
  };

  useEffect(() => {
    loadHistory();
  }, []);

  // Submit Ticket Expense
  const submitTicket = async (e) => {
    e.preventDefault();
    setMessage("");

    try {
      const res = await fetch(`${apiBase}/ticket-expenses`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          employee_id: employee.employee_id,
          ...form,
          amount: parseFloat(form.amount),
        }),
      });

      const data = await res.json();

      if (data.success) {
        setMessage("✅ Ticket Expense Added");
        loadHistory();
        setForm({
          ticket_date: "",
          purpose: "",
          assigned_to: "",
          amount: "",
        });
      } else {
        setMessage("❌ " + data.message);
      }
    } catch (error) {
      console.error(error);
      setMessage("❌ Error submitting ticket");
    }
  };

  // Delete ticket
  const deleteExpense = async (id) => {
    if (!window.confirm("Delete this record?")) return;

    try {
      const res = await fetch(`${apiBase}/ticket-expenses/${id}`, {
        method: "DELETE",
      });

      const data = await res.json();

      if (data.success) {
        setMessage("🗑 Deleted successfully");
        loadHistory();
      }
    } catch (err) {
      console.error(err);
    }
  };

  // Filter by month
  const filteredHistory =
    filterMonth === ""
      ? history
      : history.filter((t) => t.ticket_date.startsWith(filterMonth));

  return (
    <div style={{ padding: 20 }}>
      <h1 style={{ color: "#0078d4" }}>➕ Add Ticket Expense</h1>

      {/* Ticket Form */}
      <form
        onSubmit={submitTicket}
        style={{
          background: "#ffffff",
          padding: 20,
          borderRadius: 10,
          maxWidth: 500,
          boxShadow: "0 4px 12px rgba(0,0,0,0.1)",
        }}
      >
        <input
          type="date"
          value={form.ticket_date}
          required
          onChange={(e) =>
            setForm({ ...form, ticket_date: e.target.value })
          }
          style={inputStyle()}
        />

        <input
          type="text"
          placeholder="Purpose"
          value={form.purpose}
          required
          onChange={(e) =>
            setForm({ ...form, purpose: e.target.value })
          }
          style={inputStyle()}
        />

        <input
          type="text"
          placeholder="Assigned To"
          value={form.assigned_to}
          onChange={(e) =>
            setForm({ ...form, assigned_to: e.target.value })
          }
          style={inputStyle()}
        />

        <input
          type="number"
          placeholder="Amount"
          required
          value={form.amount}
          onChange={(e) =>
            setForm({ ...form, amount: e.target.value })
          }
          style={inputStyle()}
        />

        <button type="submit" style={buttonPrimary()}>
          Submit
        </button>
      </form>

      {message && <p style={{ color: "#0078d4", marginTop: 10 }}>{message}</p>}

      {/* Filter */}
      <h2 style={{ marginTop: 30 }}>🎫 Ticket Expense History</h2>

      <input
        type="month"
        value={filterMonth}
        onChange={(e) => setFilterMonth(e.target.value)}
        style={{ marginBottom: 15, padding: 8 }}
      />

      {/* History Table */}
      <table style={tableStyle()}>
        <thead>
          <tr>
            <th>Date</th>
            <th>Purpose</th>
            <th>Amount</th>
            <th>Status</th>
            <th>Delete</th>
          </tr>
        </thead>

        <tbody>
          {filteredHistory.map((item) => (
            <tr key={item.ticket_id}>
              <td>{item.ticket_date}</td>
              <td>{item.purpose}</td>
              <td>₹{item.amount}</td>
              <td>{item.status}</td>

              <td>
                <button
                  onClick={() => deleteExpense(item.ticket_id)}
                  style={deleteBtn()}
                >
                  🗑
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

/* Styles */
const inputStyle = () => ({
  width: "100%",
  padding: 10,
  marginBottom: 10,
  borderRadius: 6,
  border: "1px solid #ccc",
});

const buttonPrimary = () => ({
  padding: "10px 20px",
  background: "#0078d4",
  border: "none",
  color: "white",
  borderRadius: 6,
  cursor: "pointer",
});

const deleteBtn = () => ({
  background: "red",
  color: "white",
  border: "none",
  padding: "5px 10px",
  borderRadius: 6,
  cursor: "pointer",
});

const tableStyle = () => ({
  width: "100%",
  marginTop: 20,
  borderCollapse: "collapse",
});
